// // This is a 5-bit ring counter that rotates on a negative clock edge with an active-low synchronous reset.
module ring_counter_5bit(
    input clk,
    input reset,
    output reg [4:0] count
);
    always @(posedge clk or posedge reset) begin
        if (reset)
            count <= 5'b00001;
        else
            count <= {count[3:0], count[4]};
    end
endmodule
